SELECT forecast_method, AVG(forecast_accuracy) AS average_accuracy
FROM market_data_forecasts
GROUP BY forecast_method;

SELECT f.symbol, f.name
FROM (
  SELECT symbol
  FROM market_data
  GROUP BY symbol
  HAVING AVG(volume) > (
    SELECT AVG(volume) FROM market_data
  )
) AS high_volume_instruments
INNER JOIN financial_instruments f ON high_volume_instruments.symbol = f.symbol;

SELECT * 
FROM alerts
WHERE user_id = 'USER_ID' AND status = 'active';

SELECT symbol, AVG(predicted_close_price) AS AverageForecastedPrice
FROM market_data_forecasts
GROUP BY symbol;

SELECT user_id, COUNT(role_id) AS total_roles
FROM user_roles
GROUP BY user_id;
